import type React from "react"
import { Sparkles } from "lucide-react"
import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip"

export type AiConfidenceLevel = "high" | "medium" | "low"

/* ----------------------------------------------------------------- */
/* AiBadge — subtle "Generated by AI" marker with sparkle + tooltip.  */
/* Principle: AI assists, the user confirms. The tooltip spells that  */
/* out and lists the sources the content was derived from.            */
/* ----------------------------------------------------------------- */
export function AiBadge({
  sources = [],
  className,
}: {
  sources?: string[]
  className?: string
}) {
  const sourceList = sources.length > 0 ? sources.join(", ") : "internal data"
  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <span
          className={cn(
            "inline-flex cursor-default items-center gap-1 rounded-full border border-border bg-muted/50 px-1.5 py-0.5 text-[10px] font-medium text-muted-foreground transition-colors hover:bg-muted",
            className,
          )}
        >
          <Sparkles className="size-2.5" aria-hidden />
          Generated by AI
        </span>
      </TooltipTrigger>
      <TooltipContent className="max-w-64">
        <p className="text-pretty leading-relaxed">
          {"This was generated by AI based on "}
          <span className="font-medium text-foreground">{sourceList}</span>
          {". Verify before using in customer-facing output."}
        </p>
      </TooltipContent>
    </Tooltip>
  )
}

/* ----------------------------------------------------------------- */
/* AiConfidence — High / Medium / Low indicator using Badge.          */
/* ----------------------------------------------------------------- */
const confidenceConfig: Record<
  AiConfidenceLevel,
  { label: string; className: string }
> = {
  high: { label: "High confidence", className: "border-transparent bg-foreground text-background" },
  medium: { label: "Medium confidence", className: "border-foreground/40 bg-background text-foreground" },
  low: {
    label: "Low confidence",
    className: "border-dashed border-foreground/50 bg-background text-muted-foreground",
  },
}

export function AiConfidence({
  level,
  score,
  className,
}: {
  level: AiConfidenceLevel
  score?: number
  className?: string
}) {
  const conf = confidenceConfig[level]
  const badge = (
    <Badge className={cn("gap-1 text-[10px] font-medium", conf.className, className)}>{conf.label}</Badge>
  )
  if (score == null) return badge
  return (
    <Tooltip>
      <TooltipTrigger asChild>{badge}</TooltipTrigger>
      <TooltipContent>
        <p>
          {"Model confidence "}
          <span className="font-medium">{score.toFixed(2)}</span>
          <span className="text-muted-foreground"> / 1.00</span>
        </p>
      </TooltipContent>
    </Tooltip>
  )
}

/* ----------------------------------------------------------------- */
/* AiSources — clickable attribution chips row.                       */
/* ----------------------------------------------------------------- */
export function AiSources({
  sources,
  onSelect,
  className,
  label = "Sources",
}: {
  sources: string[]
  onSelect?: (source: string) => void
  className?: string
  label?: string
}) {
  if (sources.length === 0) return null
  return (
    <div className={cn("flex flex-wrap items-center gap-1.5", className)}>
      <span className="text-[10px] font-semibold uppercase tracking-wide text-muted-foreground">{label}</span>
      {sources.map((s) => (
        <button
          key={s}
          type="button"
          onClick={() => onSelect?.(s)}
          className="inline-flex max-w-52 items-center gap-1 truncate rounded-full border border-border bg-card px-2 py-0.5 text-[11px] font-medium text-foreground transition-colors hover:border-foreground/40 hover:bg-muted"
          title={s}
        >
          <span className="truncate">{s}</span>
        </button>
      ))}
    </div>
  )
}

/* ----------------------------------------------------------------- */
/* AiAttributionRow — convenience wrapper: AI badge + confidence in    */
/* one inline row, used in card/list headers.                          */
/* ----------------------------------------------------------------- */
export function AiAttributionRow({
  level,
  score,
  sources = [],
  className,
  children,
}: {
  level?: AiConfidenceLevel
  score?: number
  sources?: string[]
  className?: string
  children?: React.ReactNode
}) {
  return (
    <div className={cn("flex flex-wrap items-center gap-1.5", className)}>
      <AiBadge sources={sources} />
      {level && <AiConfidence level={level} score={score} />}
      {children}
    </div>
  )
}
